const normalizeText = (value = "") => String(value || "").trim().toLowerCase();

export const normalizeDirectoryRole = (value = "") => {
  const role = String(value || "").trim();
  if (!role) return "Member";
  if (role === "PL") return "Project Lead";
  if (role === "QL") return "Quality Lead";
  return role;
};

const deriveMemberRole = ({ designation = "", department = "" }) => {
  const title = normalizeText(designation);
  const dept = normalizeText(department);
  if (title.includes("tpm")) return "TPM";
  if (title.includes("project lead") || title.includes("project manager")) return "Project Lead";
  if (title.includes("quality lead") || title.includes("quality reviewer") || title.includes("qa tester")) return "Quality Lead";
  if (dept === "r&d") return "R&D";
  if (title.includes("engineer") || title.includes("developer") || title.includes("devops") || title.includes("research") || title.includes("post training") || title.includes("llm")) return "Engineer";
  if (dept.includes("operations") || dept === "engineering") return "Engineer";
  return "R&D";
};

const deriveAssignmentGroup = (role = "") => {
  if (role === "TPM") return "TPM";
  if (role === "Project Lead" || role === "Quality Lead") return "PL / QL";
  return "R&D";
};

const isRndDepartmentMember = (member = {}) => normalizeText(member.department) === "r&d";

export const PROJECT_MEMBER_DIRECTORY = RAW_PROJECT_MEMBER_DIRECTORY.map((member) => {
  const role = deriveMemberRole(member);
  return {
    ...member,
    role,
    assignmentGroup: deriveAssignmentGroup(role),
    searchLabel: [member.name, member.email, member.designation, member.department, role].filter(Boolean).join(" · "),
  };
});

export const PROJECT_MEMBER_DIRECTORY_BY_EMAIL = new Map(
  PROJECT_MEMBER_DIRECTORY.map((member) => [normalizeText(member.email), member])
);

export const findProjectDirectoryMember = ({ email = "", name = "" } = {}) => {
  const normalizedEmail = normalizeText(email);
  if (normalizedEmail && PROJECT_MEMBER_DIRECTORY_BY_EMAIL.has(normalizedEmail)) {
    return PROJECT_MEMBER_DIRECTORY_BY_EMAIL.get(normalizedEmail);
  }
  const normalizedName = normalizeText(name);
  if (!normalizedName) return null;
  return PROJECT_MEMBER_DIRECTORY.find((member) => normalizeText(member.name) === normalizedName) || null;
};

export const getProjectMembersForSection = (section = "") => {
  const normalizedSection = normalizeDirectoryRole(section);
  return PROJECT_MEMBER_DIRECTORY.filter((member) => {
    if (normalizedSection === "TPM") return member.assignmentGroup === "TPM";
    if (normalizedSection === "PL / QL") return member.assignmentGroup === "PL / QL";
    if (normalizedSection === "R&D") return member.assignmentGroup === "R&D" && isRndDepartmentMember(member);
    return true;
  });
};
